Index: .config/opencode/opencode.json
===================================================================
--- .config/opencode/opencode.json	
+++ .config/opencode/opencode.json	
@@ -1,122 +1,123 @@
 {
   "$schema": "https://opencode.ai/config.json",
   "provider": {
     "gitlab": {
       "options": {
         "instanceUrl": "https://gitlab.com"
       }
     },
     "anthropic": {
       "npm": "@ai-sdk/anthropic",
       "options": {
         "baseURL": "http://127.0.0.1:3456",
         "apiKey": "dummy"
       },
       "models": {
         "claude-opus-4-6": {
           "name": "Claude Opus 4.6"
         },
         "claude-sonnet-4-6": {
           "name": "Claude Sonnet 4.6"
         },
         "claude-haiku-4-5": {
           "name": "Claude Haiku 4.5"
         }
       }
     },
     "openai": {
       "npm": "@ai-sdk/openai",
       "models": {
         "gpt-5.5": {
           "name": "GPT-5.5"
         },
         "gpt-5.4": {
           "name": "GPT-5.4"
         }
       }
     },
     "ollama": {
       "npm": "@ai-sdk/openai-compatible",
       "name": "Ollama (local)",
       "options": {
         "baseURL": "http://localhost:11434/v1"
       },
       "models": {
         "qwen3-coder": {
           "name": "Qwen3 Coder (local)"
         },
         "qwen2.5-coder:0.5b": {
           "name": "Qwen2.5 Coder 0.5B (local, fast)"
         },
         "qwen2.5-coder:1.5b": {
           "name": "Qwen2.5 Coder 1.5B (local, balanced)"
         }
       }
     }
   },
   "model": "openai/gpt-5.5",
   "small_model": "anthropic/claude-haiku-4-5",
   "plugin": [
     "@tarquinen/opencode-dcp@latest",
+    "./plugin/opencode-with-claude.ts",
     "./plugin/claude-compat.ts",
     "./plugin/session-env.ts",
     "./plugin/nvim-open.ts"
   ],
   "autoupdate": false,
   "share": "disabled",
   "permission": "allow",
   "lsp": true,
   "agent": {
     "precise": {
       "description": "Low-temperature deterministic reasoning for correctness-critical work",
       "mode": "primary",
       "temperature": 0.1,
       "color": "secondary"
     },
     "balanced": {
       "description": "Moderate-temperature default for implementation and explanation",
       "mode": "primary",
       "temperature": 0.35,
       "color": "primary"
     },
     "creative": {
       "description": "High-temperature brainstorming for alternatives, naming, workflows, and UX",
       "mode": "primary",
       "temperature": 0.8,
       "top_p": 0.9,
       "color": "accent"
     },
     "wild": {
       "description": "Maximum-temperature divergent ideation when novelty matters more than precision",
       "mode": "primary",
       "temperature": 1,
       "top_p": 0.95,
       "color": "warning"
     }
   },
   "compaction": {
     "auto": true,
     "prune": true,
     "reserved": 4096
   },
   "tool_output": {
     "max_lines": 200,
     "max_bytes": 8192
   },
   "watcher": {
     "ignore": [
       "node_modules/**",
       "dist/**",
       ".git/**",
       "*.pyc",
       "__pycache__/**",
       ".direnv/**",
       ".beads/**",
       ".entire/**"
     ]
   },
   "instructions": [
     "AGENTS.md",
     "CLAUDE.md"
   ]
 }
